<?php

namespace Database\Seeders;

use App\Models\ContentTemplate;
use Illuminate\Database\Seeder;

class NicheTemplateSeeder extends Seeder
{
    public function run(): void
    {
        $templates = array_merge(
            $this->initialTemplates(),
            $this->replyTemplates(),
            $this->closingTemplates()
        );

        $seeded = 0;
        foreach ($templates as $t) {
            ContentTemplate::updateOrCreate(
                ['content_fingerprint' => md5($t['body'] . ($t['subject'] ?? ''))],
                array_merge($t, [
                    'is_active' => true,
                    'warmup_stage' => $t['warmup_stage'] ?? 'any',
                    'cooldown_minutes' => $t['cooldown_minutes'] ?? rand(45, 120),
                    'greetings' => $t['greetings'] ?? ['Hi', 'Hello', 'Hey', 'Hey there', 'Good morning', 'Good afternoon'],
                    'signoffs' => $t['signoffs'] ?? ['Best', 'Thanks', 'Regards', 'Cheers', 'Talk soon', 'Best regards'],
                ])
            );
            $seeded++;
        }

        echo "Seeded {$seeded} niche warmup templates.\n";
    }

